mapper.select:
SELECT 
FROM report
WHERE reporter_id = #{reporterId}
ORDER BY report_time DESC
LIMIT #{offset}, #{limit}

SELECT 
FROM report
WHERE target_type = #{targetType} AND target_id = #{targetId}
ORDER BY report_time DESC
LIMIT #{offset}, #{limit}

SELECT 
FROM report
WHERE status = #{status}
ORDER BY report_time DESC
LIMIT #{offset}, #{limit}

mapper.insert:
INSERT INTO report (
    report_id, reporter_id, target_type, target_id, reason, status, report_time
) VALUES (
    #{reportId}, #{reporterId}, #{targetType}, #{targetId}, #{reason}, #{status}, NOW()
)

mapper.update:
UPDATE report
SET status = #{status},
    handler_id = #{handlerId},
    handle_time = NOW(),
    handle_result = #{handleResult}
WHERE report_id = #{reportId}
